import React, { useState } from 'react';
import axios from 'axios';
import { Droplet, Loader2, AlertCircle, CheckCircle } from 'lucide-react';
import { motion } from 'framer-motion';

const KidneyPage = () => {
    const [formData, setFormData] = useState({
        age: '', blood_pressure: '', specific_gravity: '', albumin: '', sugar: '',
        red_blood_cells: '', pus_cell: '', pus_cell_clumps: '', bacteria: '',
        blood_glucose_random: '', blood_urea: '', serum_creatinine: '', sodium: '',
        potassium: '', haemoglobin: '', packed_cell_volume: '', white_blood_cell_count: '',
        red_blood_cell_count: '', hypertension: '', diabetes_mellitus: '',
        coronary_artery_disease: '', appetite: '', peda_edema: '', aanemia: ''
    });
    const [result, setResult] = useState(null);
    const [loading, setLoading] = useState(false);

    const handleChange = (e) => setFormData({ ...formData, [e.target.name]: e.target.value });

    const handleSubmit = async (e) => {
        e.preventDefault();
        setLoading(true);
        try {
            const payload = Object.fromEntries(
                Object.entries(formData).map(([k, v]) => [k, parseFloat(v) || 0])
            );
            const response = await axios.post('http://localhost:8000/api/predict/kidney', payload);
            setResult(response.data);
        } catch (error) {
            console.error("Error:", error);
        } finally {
            setLoading(false);
        }
    };

    const formFields = [
        { name: 'age', label: 'Age' }, { name: 'blood_pressure', label: 'BP' },
        { name: 'specific_gravity', label: 'Specific Gravity' }, { name: 'albumin', label: 'Albumin' },
        { name: 'sugar', label: 'Sugar' }, { name: 'red_blood_cells', label: 'RBC (0/1)' },
        { name: 'blood_glucose_random', label: 'BGR' }, { name: 'blood_urea', label: 'Blood Urea' },
        { name: 'serum_creatinine', label: 'Creatinine' }, { name: 'haemoglobin', label: 'Hemoglobin' },
        { name: 'packed_cell_volume', label: 'PCV' }, { name: 'white_blood_cell_count', label: 'WBC Count' },
        { name: 'hypertension', label: 'Hypertension (1/0)' }, { name: 'diabetes_mellitus', label: 'Diabetes (1/0)' }
    ]; // Truncated list for brevity in UI, but logic supports all

    return (
        <div className="max-w-5xl mx-auto px-4 py-12">
            <div className="text-center mb-12">
                <div className="inline-flex p-3 rounded-xl bg-teal-50 text-teal-600 mb-4"><Droplet size={32} /></div>
                <h1 className="text-3xl md:text-4xl mb-4">Kidney Health</h1>
                <p className="text-muted">Enter renal health metrics.</p>
            </div>

            <div className="grid lg:grid-cols-3 gap-8">
                <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="lg:col-span-2">
                    <form onSubmit={handleSubmit} className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100">
                        <div className="grid grid-cols-2 md:grid-cols-3 gap-4 mb-6">
                            {Object.keys(formData).map(key => (
                                <div key={key}>
                                    <label className="block text-xs font-medium text-gray-500 mb-1 capitalize">{key.replace(/_/g, ' ')}</label>
                                    <input type="number" name={key} value={formData[key]} onChange={handleChange} className="w-full px-2 py-1.5 rounded border border-gray-200 text-sm" />
                                </div>
                            ))}
                        </div>
                        <button type="submit" disabled={loading} className="w-full py-3 bg-primary text-white rounded-xl font-semibold">
                            {loading ? 'Analyzing...' : 'Predict'}
                        </button>
                    </form>
                </motion.div>

                <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }}>
                    {result ? (
                        <div className={`h-full p-6 rounded-2xl border ${result.prediction === 'Positive' ? 'bg-red-50 border-red-100' : 'bg-green-50 border-green-100'}`}>
                            <h3 className="text-xl font-bold mb-2">{result.prediction}</h3>
                            <p className="mb-4">Risk: {result.risk_level}</p>
                            <ul className="text-sm space-y-2">{result.recommendations.map((r, i) => <li key={i}>• {r}</li>)}</ul>
                        </div>
                    ) : (
                        <div className="h-full bg-gray-50 rounded-2xl border border-gray-100 flex items-center justify-center p-8 text-center text-gray-400">
                            <p>Results will appear here.</p>
                        </div>
                    )}
                </motion.div>
            </div>
        </div>
    );
};

export default KidneyPage;
